import React from 'react';

const Home = () => {
  return (
    <div style={{ padding: '10px' }}>
      {/* Live Tracking Map Section */}
      <div style={{ background: '#e0f7fa', padding: '20px', borderRadius: '15px', marginBottom: '20px', border: '1px solid #b2ebf2' }}>
        <h4 style={{ margin: '0' }}>📍 Live Tracking</h4>
        <p style={{ fontSize: '13px' }}>Lahore to Karachi | Est. 3-4 Days</p>
        <button style={{ background: '#0056b3', color: '#fff', border: 'none', padding: '8px 20px', borderRadius: '5px' }}>Track Shipment</button>
      </div>

      {/* Categories Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '10px' }}>
        {['Domestic', 'Intl', 'Cargo', 'Air', 'Road'].map((cat) => (
          <div style={{ textAlign: 'center', fontSize: '10px', background: '#fff', padding: '10px', borderRadius: '10px' }}>
            📦<br/>{cat}
          </div>
        ))}
      </div>
    </div>
  );
};
export default Home;
